dashboard.definition:
{
    "title": "Domain",
    "description": "Gain comprehensive insights into network performance including utilization, congestion, and error rates for all Network Objects within IMM, Standalone and Unified Edge targets. This dashboard leverages both Inventory and Network Metrics data sources to deliver a unified, correlated view of network health and performance across your infrastructure.",
    "inputs": {
        "input_DWNtKVDG": {
            "context": {
                "formattedConfig": {
                    "number": {
                        "prefix": ""
                    }
                },
                "formattedStatics": ">statics | formatByType(formattedConfig)",
                "label": ">primary | seriesByName(\"account_name\") | renameSeries(\"label\") | formatByType(formattedConfig)",
                "statics": [
                    [
                        "All"
                    ],
                    [
                        "*"
                    ]
                ],
                "value": ">primary | seriesByName(\"account_name\") | renameSeries(\"value\") | formatByType(formattedConfig)"
            },
            "dataSources": {
                "primary": "ds_mFgnShzC"
            },
            "options": {
                "defaultValue": [
                    "*"
                ],
                "items": ">frame(label, value) | prepend(formattedStatics) | objects()",
                "token": "account_name"
            },
            "title": "Intersight Account Name",
            "type": "input.multiselect"
        },
        "input_F0hY1ofj": {
            "options": {
                "defaultValue": "*",
                "prefix": "*",
                "suffix": "*",
                "token": "errors_port_name"
            },
            "title": "Port Name",
            "type": "input.text"
        },
        "input_Xdl4x1T6": {
            "options": {
                "defaultValue": "timechart",
                "items": [
                    {
                        "label": "Auto",
                        "value": "timechart"
                    },
                    {
                        "label": "15 Minute",
                        "value": "timechart span=15m"
                    },
                    {
                        "label": "30 Minute",
                        "value": "timechart span=30m"
                    },
                    {
                        "label": "1 Hour",
                        "value": "timechart span=1h"
                    }
                ],
                "token": "granularity"
            },
            "title": "Granularity for Linecharts",
            "type": "input.dropdown"
        },
        "input_global_trp": {
            "options": {
                "defaultValue": "-24h@h,now",
                "token": "time_range"
            },
            "title": "Select Time Range",
            "type": "input.timerange"
        },
        "input_lL7jpA9T": {
            "context": {
                "formattedConfig": {
                    "number": {
                        "prefix": ""
                    }
                },
                "formattedStatics": ">statics | formatByType(formattedConfig)",
                "label": ">primary | seriesByName(\"event.DomainName\") | renameSeries(\"label\") | formatByType(formattedConfig)",
                "statics": [
                    [
                        "All"
                    ],
                    [
                        "*"
                    ]
                ],
                "value": ">primary | seriesByName(\"event.DomainId\") | renameSeries(\"value\") | formatByType(formattedConfig)"
            },
            "dataSources": {
                "primary": "ds_HDwPB51A"
            },
            "options": {
                "defaultValue": [
                    "*"
                ],
                "items": ">frame(label, value) | prepend(formattedStatics) | objects()",
                "token": "select_domain"
            },
            "title": "Select Domains",
            "type": "input.multiselect"
        },
        "input_vBipVYTY": {
            "context": {},
            "dataSources": {},
            "options": {
                "defaultValue": "false",
                "items": [
                    {
                        "label": "Exclude zero values",
                        "value": "false"
                    },
                    {
                        "label": "Include zero values",
                        "value": "true"
                    }
                ],
                "token": "show_zero_values"
            },
            "title": "",
            "type": "input.dropdown"
        }
    },
    "defaults": {
        "dataSources": {
            "ds.search": {
                "options": {
                    "queryParameters": {
                        "earliest": "$global_time.earliest$",
                        "latest": "$global_time.latest$"
                    }
                }
            }
        }
    },
    "visualizations": {
        "viz_0Js2d7ws": {
            "dataSources": {
                "primary": "ds_9cUNf2gC"
            },
            "description": "This panel displays domain-level network congestion by visualizing receive pause frames and priority pause protocol (PPP) frames. These metrics help identify congestion issues at the receiver level, offering insights into traffic flow interruptions and QoS-related throttling across network domains.",
            "eventHandlers": [
                {
                    "options": {
                        "tokens": [
                            {
                                "key": "row._event_id.value",
                                "token": "clicked_receive_congestion"
                            },
                            {
                                "key": "row.Port Name.value",
                                "token": "clicked_receive_congestion_name"
                            }
                        ]
                    },
                    "type": "drilldown.setToken"
                }
            ],
            "options": {
                "count": 5,
                "drilldown": "row",
                "showInternalFields": false
            },
            "showProgressBar": true,
            "title": "Receive Pause Frames",
            "type": "splunk.table"
        },
        "viz_48OtOyXG": {
            "dataSources": {
                "primary": "ds_UN22HRpU"
            },
            "hideWhenNoData": true,
            "showProgressBar": true,
            "title": "Storage Receive Traffic FI-A (Sum): '$clicked_domain_name_storage$'",
            "type": "splunk.singlevalue"
        },
        "viz_5Q7OOnVf": {
            "dataSources": {
                "primary": "ds_i3LK2l31"
            },
            "description": "This panel displays Fibre Channel uplink traffic distribution. It helps monitor traffic patterns, detect bottlenecks, and ensure balanced utilization across FC and FCoE-based uplinks in the network fabric.",
            "eventHandlers": [
                {
                    "options": {
                        "tokens": [
                            {
                                "key": "row._domain_id.value",
                                "token": "clicked_domain_storage"
                            },
                            {
                                "key": "row.Domain Name.value",
                                "token": "clicked_domain_name_storage"
                            },
                            {
                                "key": "row._tx_a_avg.value",
                                "token": "_tx_a_avg_fibre"
                            },
                            {
                                "key": "row._tx_b_avg.value",
                                "token": "_tx_b_avg_fibre"
                            },
                            {
                                "key": "row._rx_a_avg.value",
                                "token": "_rx_a_avg_fibre"
                            },
                            {
                                "key": "row._rx_b_avg.value",
                                "token": "_rx_b_avg_fibre"
                            }
                        ]
                    },
                    "type": "drilldown.setToken"
                }
            ],
            "options": {
                "count": 5,
                "data": {
                    "fields": [
                        {
                            "name": "Domain Name"
                        }
                    ]
                },
                "dataOverlayMode": "none",
                "drilldown": "row",
                "showInternalFields": false
            },
            "showProgressBar": true,
            "title": "Traffic Distribution Fibre Channel Uplinks",
            "type": "splunk.table"
        },
        "viz_5pup8hmj": {
            "dataSources": {
                "primary": "ds_qFZSKKiQ"
            },
            "hideWhenNoData": true,
            "options": {
                "legendTruncation": "ellipsisMiddle",
                "nullValueDisplay": "connect",
                "showRoundedY2AxisLabels": false,
                "showY2MajorGridLines": true,
                "xAxisLabelRotation": -45,
                "xAxisTitleText": "Timestamp",
                "xAxisTitleVisibility": "hide",
                "y2AxisAbbreviation": "off",
                "yAxisAbbreviation": "off",
                "yAxisTitleText": "KB",
                "yAxisTitleVisibility": "hide"
            },
            "showProgressBar": true,
            "title": "Transmit Pause Frames per selected port: '$clicked_transmit_congestion_name$'",
            "type": "splunk.line"
