        "viz_yboqdNaK": {
            "dataSources": {
                "primary": "ds_BOH96skN"
            },
            "description": "This panel shows Ethernet uplink traffic distribution. It helps identify imbalances, detect anomalies, and optimize uplink performance across domain-level network infrastructure.",
            "eventHandlers": [
                {
                    "options": {
                        "tokens": [
                            {
                                "key": "row._domain_id.value",
                                "token": "clicked_domain"
                            },
                            {
                                "key": "row.Domain Name.value",
                                "token": "clicked_domain_name"
                            },
                            {
                                "key": "row._tx_a_avg.value",
                                "token": "_tx_a_avg"
                            },
                            {
                                "key": "row._tx_b_avg.value",
                                "token": "_tx_b_avg"
                            },
                            {
                                "key": "row._rx_a_avg.value",
                                "token": "_rx_a_avg"
                            },
                            {
                                "key": "row._rx_b_avg.value",
                                "token": "_rx_b_avg"
                            }
                        ]
                    },
                    "type": "drilldown.setToken"
                }
            ],
            "options": {
                "count": 5,
                "data": {
                    "fields": [
                        {
                            "name": "Domain Name"
                        }
                    ]
                },
                "dataOverlayMode": "none",
                "drilldown": "row",
                "showInternalFields": false
            },
            "showProgressBar": true,
            "title": "Utilization - Traffic Distribution Ethernet Uplinks",
            "type": "splunk.table"
        }
    },
    "dataSources": {
        "ds_5sCA35Vp": {
            "name": "Storage Receive Utilization FI-A _Sum__ __clicked_domain_name_storage__ search",
            "options": {
                "query": "| tstats fillnull_value=\"-\" `cisco_intersight_summariesonly` count\n    sum(\"cisco_intersight.cisco_intersight_network.network_io_receive\") as total_nirs\n    from datamodel=Cisco_Intersight\n    where nodename=cisco_intersight.cisco_intersight_network\n        AND \"cisco_intersight.cisco_intersight_network.network_domain_id\" = $clicked_domain_storage$\n        AND \"cisco_intersight.cisco_intersight_network.network_port_role\" IN (\"fc_uplink\", \"fc_storage\", \"fcoe_uplink\", \"fcoe_storage\", \"appliance\")\n        AND \"cisco_intersight.cisco_intersight_network.network_host_name\" = \"*FI-A\"\n    by _time, \"cisco_intersight.cisco_intersight_network.network_name\"\n    span=15m\n\n| eval nirs_mb = `cisco_intersight_bytes_to_given_unit(total_nirs, $_rx_a_avg_fibre$)`\n\n|  $granularity$ sum(nirs_mb) AS \"Network IO Receive (Sum)\" by \"cisco_intersight.cisco_intersight_network.network_name\"",
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                },
                "refresh": "15m",
                "refreshType": "delay"
            },
            "type": "ds.search"
        },
        "ds_6G4JaI9N": {
            "name": "Eth Transmit Utilization FI-A _Sum__ __clicked_domain_name__ search",
            "options": {
                "query": "| tstats fillnull_value=\"-\" `cisco_intersight_summariesonly` count\n    sum(\"cisco_intersight.cisco_intersight_network.network_io_transmit\") as total_nits\n    from datamodel=Cisco_Intersight\n    where nodename=cisco_intersight.cisco_intersight_network\n        AND \"cisco_intersight.cisco_intersight_network.network_domain_id\" = $clicked_domain$\n        AND \"cisco_intersight.cisco_intersight_network.network_port_role\" = \"eth_uplink\"\n        AND \"cisco_intersight.cisco_intersight_network.network_port_type\" = \"ethernet\"\n        AND \"cisco_intersight.cisco_intersight_network.network_host_name\" = \"*FI-A\"\n    by _time, \"cisco_intersight.cisco_intersight_network.network_name\"\n    span=15m\n\n| eval nits_mb = `cisco_intersight_bytes_to_given_unit(total_nits, $_tx_a_avg$)`\n\n| $granularity$ sum(nits_mb) as \"Network IO Transmit (Sum)\" by \"cisco_intersight.cisco_intersight_network.network_name\"",
                "queryParameters": {
