            "options": {
                "query": "| tstats fillnull_value=\"-\" `cisco_intersight_summariesonly` count\n       sum(\"cisco_intersight.cisco_intersight_network.network_io_receive\") as total_nirs\n       sum(\"cisco_intersight.cisco_intersight_network.network_io_transmit\") as total_nits\n       from datamodel=Cisco_Intersight\n       where nodename=cisco_intersight.cisco_intersight_network\n       AND \"cisco_intersight.cisco_intersight_network.network_domain_id\" IN ($select_domain$)\n       AND \"cisco_intersight.cisco_intersight_network.network_port_role\" IN (\"eth_uplink\")\n       AND \"cisco_intersight.cisco_intersight_network.network_port_type\" IN (\"ethernet\")\n       AND \"cisco_intersight.cisco_intersight_network.network_account_name\" IN ($account_name$)\n       by \"cisco_intersight.cisco_intersight_network.network_domain_name\",\n          \"cisco_intersight.cisco_intersight_network.network_domain_id\",\n          \"cisco_intersight.cisco_intersight_network.network_host_name\", \"cisco_intersight.cisco_intersight_network.network_account_name\", _time\n       span=1m\n\n| rex field=\"cisco_intersight.cisco_intersight_network.network_host_name\" \"(?<fi_type>FI-[AB])\"\n\n| eval fi_type_tx = fi_type . \"_tx\", fi_type_rx = fi_type . \"_rx\"\n| eval {fi_type_tx} = total_nits, {fi_type_rx} = total_nirs\n\n| stats \n    sum(FI-A_tx) as tx_a, \n    sum(FI-A_rx) as rx_a, \n    sum(FI-B_tx) as tx_b, \n    sum(FI-B_rx) as rx_b,\n    avg(FI-A_tx) as tx_a_avg, \n    avg(FI-A_rx) as rx_a_avg, \n    avg(FI-B_tx) as tx_b_avg, \n    avg(FI-B_rx) as rx_b_avg\n    by \"cisco_intersight.cisco_intersight_network.network_domain_name\", \"cisco_intersight.cisco_intersight_network.network_domain_id\"\n\n| eval \n    tx_a = coalesce(tx_a, 0), \n    tx_b = coalesce(tx_b, 0), \n    rx_a = coalesce(rx_a, 0), \n    rx_b = coalesce(rx_b, 0),\n    total_combined_tx = tx_a + tx_b,\n    total_combined_rx = rx_a + rx_b\n\n| where \"$show_zero_values$\"=\"true\" \n      OR (total_combined_tx != 0 or total_combined_rx != 0)\n\n| eval \n    \"Total Transmit FI-A\" = `cisco_intersight_human_readable_bytes(tx_a)`.\" \".`cisco_intersight_human_readable_unit(tx_a)`,\n    \"Total Transmit FI-B\" = `cisco_intersight_human_readable_bytes(tx_b)`.\" \".`cisco_intersight_human_readable_unit(tx_b)`,\n    \"Total Receive FI-A\" = `cisco_intersight_human_readable_bytes(rx_a)`.\" \".`cisco_intersight_human_readable_unit(rx_a)`,\n    \"Total Receive FI-B\" = `cisco_intersight_human_readable_bytes(rx_b)`.\" \".`cisco_intersight_human_readable_unit(rx_b)`,\n    \"Total Transmit\" = `cisco_intersight_human_readable_bytes(total_combined_tx)`.\" \".`cisco_intersight_human_readable_unit(total_combined_tx)`,\n    \"Total Receive\" = `cisco_intersight_human_readable_bytes(total_combined_rx)`.\" \".`cisco_intersight_human_readable_unit(total_combined_rx)`,\n    _tx_a_avg = `cisco_intersight_human_readable_unit(tx_a_avg)`, _rx_a_avg = `cisco_intersight_human_readable_unit(rx_a_avg)`, _tx_b_avg = `cisco_intersight_human_readable_unit(tx_b_avg)`, _rx_b_avg = `cisco_intersight_human_readable_unit(rx_b_avg)`\n\n| rename \"cisco_intersight.cisco_intersight_network.network_domain_name\" as \"Domain Name\", \n         \"cisco_intersight.cisco_intersight_network.network_domain_id\" as event.DomainId, event.DomainId as _domain_id\n\n| table \"Domain Name\", \"Total Transmit\", \"Total Transmit FI-A\", \"Total Transmit FI-B\", \"Total Receive\", \"Total Receive FI-A\", \"Total Receive FI-B\", _domain_id, _tx_a_avg, _rx_a_avg, _tx_b_avg, _rx_b_avg",
                "queryParameters": {
