        "ds_gsJFSJgX": {
            "name": "Domain Errors - Overview search",
            "options": {
                "query": "| tstats fillnull_value=\"-\" `cisco_intersight_summariesonly` \n    sum(cisco_intersight.cisco_intersight_network.network_receive_discard_error_sum) as enrds,\n    sum(cisco_intersight.cisco_intersight_network.network_too_short_error_sum) as enrtss,\n    sum(cisco_intersight.cisco_intersight_network.network_no_buffer_sum) as enrnbs,\n    sum(cisco_intersight.cisco_intersight_network.network_crc_duration_sum) as ncrccs,\n    sum(cisco_intersight.cisco_intersight_network.network_too_long_error_sum) as enrtls,\n    sum(cisco_intersight.cisco_intersight_network.network_runt_error_sum) as nrrs,\n    sum(cisco_intersight.cisco_intersight_network.network_transmit_jabber_error_sum) as entjs,\n    sum(cisco_intersight.cisco_intersight_network.network_transmit_discard_error_sum) as entds,\n    sum(cisco_intersight.cisco_intersight_network.network_carrier_sense_error_sum) as encss,\n    sum(cisco_intersight.cisco_intersight_network.network_late_collisions_error_sum) as enlcs,\n    sum(cisco_intersight.cisco_intersight_network.network_transmit_deferred_error_sum) as entdfs\n    from datamodel=Cisco_Intersight\n    where nodename=cisco_intersight.cisco_intersight_network \n        AND cisco_intersight.cisco_intersight_network.network_domain_id IN ($select_domain$)\n        AND cisco_intersight.cisco_intersight_network.network_account_name IN ($account_name$)\n        AND cisco_intersight.cisco_intersight_network.network_name=\"*$errors_port_name$*\"\n        AND NOT cisco_intersight.cisco_intersight_network.network_port_role IN (\"unconfigured\", \"server_pc\", \"fabric_pc\", \"host_pc\", \"vethernet\", \"vfc\", \"vnic\", \"vhba\", \"eth_uplink_pc\")\n    by \n        \"cisco_intersight.cisco_intersight_network.network_domain_name\",\n        \"cisco_intersight.cisco_intersight_network.network_host_name\",\n        \"cisco_intersight.cisco_intersight_network.network_port_role\",\n        \"cisco_intersight.cisco_intersight_network.network_name\",\n        \"cisco_intersight.cisco_intersight_network.network_id\",\n        \"cisco_intersight.cisco_intersight_network.network_account_name\"\n\n| where (\"$show_zero_values$\"=\"false\" \n   AND ((enrds != 0 AND isnotnull(enrds)) OR (enrtss != 0 AND isnotnull(enrtss)) OR (enrnbs != 0 AND isnotnull(enrnbs)) OR (ncrccs != 0 AND isnotnull(ncrccs)) OR (enrtls != 0 AND isnotnull(enrtls)) OR (nrrs != 0 AND isnotnull(nrrs)) OR (entjs != 0 AND isnotnull(entjs)) OR (entds != 0 AND isnotnull(entds)) OR (encss != 0 AND isnotnull(encss)) OR (enlcs != 0 AND isnotnull(enlcs)) OR (entdfs != 0 AND isnotnull(entdfs)))) OR (\"$show_zero_values$\"=\"true\" AND (isnotnull(enrds) OR isnotnull(enrtss) OR isnotnull(enrnbs) OR isnotnull(ncrccs) OR isnotnull(enrtls) OR isnotnull(nrrs) OR isnotnull(entjs) OR isnotnull(entds) OR isnotnull(encss) OR isnotnull(enlcs) OR isnotnull(entdfs)))\n\n| eval rx_sum = enrds + enrtss + enrnbs + ncrccs + enrtls + nrrs\n| eval tx_sum = entjs + entds + encss + enlcs + entdfs\n| eval total = rx_sum + tx_sum\n| rex field=cisco_intersight.cisco_intersight_network.network_host_name \"FI-(?<FI>[AB])\"\n| rename \n    cisco_intersight.cisco_intersight_network.network_domain_name as \"Domain Name\",\n    cisco_intersight.cisco_intersight_network.network_port_role as \"Network Port Role\",\n    cisco_intersight.cisco_intersight_network.network_name as \"Port Name\",\n    cisco_intersight.cisco_intersight_network.network_id as _event_id,\n    nrrs as Runt,\n    enrtls as \"Too Long\",\n    enrnbs as \"No Buffer\",\n    enrtss as \"Too Short\",\n    enrds as \"Receive Discard\",\n    entds as \"Transmit Discard\",\n    entdfs as \"Transmit Deferred\",\n    enlcs as \"Late Collision\",\n    encss as \"Carrier Sense\",\n    entjs as Jabber,\n    ncrccs as CRC,\n    rx_sum as \"Receive Errors Sum\",\n    tx_sum as \"Transmit Errors Sum\",\n    total as \"Total Errors\"\n| table \"Domain Name\", FI, \"Network Port Role\", \"Port Name\", \"Total Errors\", \"Receive Errors Sum\", \"Receive Discard\", \"Too Short\", \"No Buffer\", \"CRC\", \"Too Long\", \"Runt\", \"Transmit Errors Sum\", \"Jabber\", \"Transmit Discard\", \"Carrier Sense\", \"Late Collision\", \"Transmit Deferred\", _event_id\n| sort \"Network Port Role\"",
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                },
                "refresh": "15m",
                "refreshType": "delay"
            },
            "type": "ds.search"
        },
        "ds_i3LK2l31": {
            "name": "Traffic Distribution Fibre Channel Uplinks search",
            "options": {
                "query": "| tstats fillnull_value=\"-\" `cisco_intersight_summariesonly` count\n       sum(\"cisco_intersight.cisco_intersight_network.network_io_receive\") as total_nirs\n       sum(\"cisco_intersight.cisco_intersight_network.network_io_transmit\") as total_nits,\n       from datamodel=Cisco_Intersight\n       where nodename=cisco_intersight.cisco_intersight_network\n       AND \"cisco_intersight.cisco_intersight_network.network_domain_id\" IN ($select_domain$)\n       AND \"cisco_intersight.cisco_intersight_network.network_account_name\" IN ($account_name$)\n       AND \"cisco_intersight.cisco_intersight_network.network_port_role\" IN (\"fc_uplink\", \"fc_storage\", \"fcoe_uplink\", \"fcoe_storage\", \"appliance\")\n       by \"cisco_intersight.cisco_intersight_network.network_domain_name\",\n          \"cisco_intersight.cisco_intersight_network.network_domain_id\",\n          \"cisco_intersight.cisco_intersight_network.network_host_name\", _time, \"cisco_intersight.cisco_intersight_network.network_account_name\"\n       span=1m\n\n| rex field=\"cisco_intersight.cisco_intersight_network.network_host_name\" \"(?<fi_type>FI-[AB])\"\n\n| eval fi_type_tx = fi_type . \"_tx\", fi_type_rx = fi_type . \"_rx\"\n| eval {fi_type_tx} = total_nits, {fi_type_rx} = total_nirs\n\n| stats \n    sum(FI-A_tx) as tx_a, \n    sum(FI-A_rx) as rx_a, \n    sum(FI-B_tx) as tx_b, \n    sum(FI-B_rx) as rx_b,\n    avg(FI-A_tx) as tx_a_avg, \n    avg(FI-A_rx) as rx_a_avg, \n    avg(FI-B_tx) as tx_b_avg, \n    avg(FI-B_rx) as rx_b_avg\n    by \"cisco_intersight.cisco_intersight_network.network_domain_name\", \"cisco_intersight.cisco_intersight_network.network_domain_id\"\n\n| eval \n    tx_a = coalesce(tx_a, 0), \n    tx_b = coalesce(tx_b, 0), \n    rx_a = coalesce(rx_a, 0), \n    rx_b = coalesce(rx_b, 0),\n    total_combined_tx = tx_a + tx_b,\n    total_combined_rx = rx_a + rx_b\n\n| where \"$show_zero_values$\"=\"true\" \n      OR (total_combined_tx != 0 or total_combined_rx != 0)\n\n| eval \n    \"Total Transmit FI-A\" = `cisco_intersight_human_readable_bytes(tx_a)`.\" \".`cisco_intersight_human_readable_unit(tx_a)`,\n    \"Total Transmit FI-B\" = `cisco_intersight_human_readable_bytes(tx_b)`.\" \".`cisco_intersight_human_readable_unit(tx_b)`,\n    \"Total Receive FI-A\" = `cisco_intersight_human_readable_bytes(rx_a)`.\" \".`cisco_intersight_human_readable_unit(rx_a)`,\n    \"Total Receive FI-B\" = `cisco_intersight_human_readable_bytes(rx_b)`.\" \".`cisco_intersight_human_readable_unit(rx_b)`,\n    \"Total Transmit\" = `cisco_intersight_human_readable_bytes(total_combined_tx)`.\" \".`cisco_intersight_human_readable_unit(total_combined_tx)`,\n    \"Total Receive\" = `cisco_intersight_human_readable_bytes(total_combined_rx)`.\" \".`cisco_intersight_human_readable_unit(total_combined_rx)`,\n    _tx_a_avg = `cisco_intersight_human_readable_unit(tx_a_avg)`, _rx_a_avg = `cisco_intersight_human_readable_unit(rx_a_avg)`, _tx_b_avg = `cisco_intersight_human_readable_unit(tx_b_avg)`, _rx_b_avg = `cisco_intersight_human_readable_unit(rx_b_avg)`\n\n| rename \"cisco_intersight.cisco_intersight_network.network_domain_name\" as \"Domain Name\", \n         \"cisco_intersight.cisco_intersight_network.network_domain_id\" as _domain_id\n\n| table \"Domain Name\", \"Total Transmit\", \"Total Transmit FI-A\", \"Total Transmit FI-B\", \"Total Receive\", \"Total Receive FI-A\", \"Total Receive FI-B\", _domain_id, _tx_a_avg, _rx_a_avg, _tx_b_avg, _rx_b_avg",
                "queryParameters": {
                    "earliest": "$time_range.earliest$",
                    "latest": "$time_range.latest$"
                },
                "refresh": "15m",
                "refreshType": "delay"
            },
            "type": "ds.search"
        },
